mapper.select:
SELECT * FROM knowledge_bases
WHERE user_id = #{userId} AND file_name = #{fileName}
LIMIT 1

SELECT id, content, metadata,
       (1 - (embedding <=> #{queryVec}::vector)) AS similarity
FROM public.vector_store
WHERE (1 - (embedding <=> #{queryVec}::vector)) >= #{threshold}
  AND metadata ->> 'userId' = #{userId}::text
  AND metadata ->> 'category' = #{category}
ORDER BY similarity DESC
LIMIT #{topK}
